// Enriquecer cada item con el ticker original y detectar fallos de FMP más robustamente
const items = $input.all();
const allWatchlist = $('Read Watchlist').all();

return items.map((item, idx) => {
  const ticker = allWatchlist[idx]?.json?.Ticker || 'UNKNOWN';
  const jsonStr = JSON.stringify(item.json);
  // Detectar errores o ausencia de datos relevantes
  const hasError = jsonStr.includes('Error Message') || jsonStr.includes('Legacy Endpoint') || jsonStr.includes('Limit Reach');
  // Verificar campos críticos que deberían existir en la respuesta de FMP Metrics
  const hasMetrics = item.json && Object.keys(item.json).length > 0 && item.json.marketCap != null;
  const fmpFailed = hasError || !hasMetrics;

  return {
    json: {
      ...item.json,
      _ticker: ticker,
      _fmpFailed: fmpFailed
    }
  };
});

// Combinar RSI de Alpha Vantage con el _ticker del IF FALSE branch
const rsiItems = $input.all();
let ifFalseItems = [];
try { ifFalseItems = $('FMP Fallo?').all(); } catch(e) {}

return rsiItems.map((item, idx) => {
  const rsiData = item.json || {};
  const ticker = ifFalseItems[idx]?.json?._ticker || rsiData['Meta Data']?.['1: Symbol'] || 'UNKNOWN';
  let rsiVal = null;
  let rsiSource = 'NONE';
  if (rsiData['Technical Analysis: RSI']) {
    const dates = Object.keys(rsiData['Technical Analysis: RSI']);
    if (dates.length > 0) {
      rsiVal = parseFloat(rsiData['Technical Analysis: RSI'][dates[0]].RSI);
      rsiSource = 'Alpha Vantage';
    }
  }
  return {
    json: {
      _ticker: ticker,
      _rsiAlpha: rsiVal,
      _rsiSource: rsiSource,
      _needsFinvizRsi: rsiVal === null
    }
  };
});

// Score FMP - Fixed ticker lookup
const finvizFull = [];
try {
  const fv = $('Finviz Extract').all();
  if (Array.isArray(fv)) finvizFull.push(...fv);
} catch(e) { console.log('Finviz Extract error:', e.message); }

const finvizMap = {};
finvizFull.forEach(item => {
  const t = item?.json?._ticker || '';
  if(t) finvizMap[t] = item.json;
});

const checkRsiItems = $('Check RSI').all();
const allProfile = $('FMP Profile').all();
const allRatios = $('FMP Ratios').all();
const allMetrics = $('FMP Metrics').all();

console.log('=== Score FMP Debug ===');
console.log('checkRsiItems:', checkRsiItems.length);
console.log('allProfile:', allProfile.length);

const results = [];

const parseNum = val => {
  if(!val || val === '-') return null;
  const c = String(val).replace(/[%,]/g, '');
  const n = parseFloat(c);
  return isNaN(n) ? null : n;
};

// Robust ticker finder - handles multiple response formats
const findByTicker = (arr, ticker) => {
  if (!arr || !Array.isArray(arr)) return { json: {} };

  for (const item of arr) {
    if (!item?.json) continue;
    const j = item.json;

    // Handle array response format from FMP
    if (Array.isArray(j)) {
      const found = j.find(it => it?.symbol === ticker || it?.Ticker === ticker);
      if (found) return { json: found };
    }

    // Handle object with symbol directly
    if (j.symbol === ticker || j.Ticker === ticker || j._ticker === ticker) {
      return item;
    }
  }
  return { json: {} };
};

for(let i = 0; i < checkRsiItems.length; i++) {
  const check = checkRsiItems[i]?.json;
  if(!check) continue;

  if(check._fmpFailed) {
    console.log('Skipping FMP failed:', check._ticker);
    continue;
  }

  const ticker = check._ticker;
  console.log('Processing ticker:', ticker);

  const profile = findByTicker(allProfile, ticker).json || {};
  const ratios = findByTicker(allRatios, ticker).json || {};
  const metrics = findByTicker(allMetrics, ticker).json || {};

  console.log('Profile found:', !!profile?.symbol, 'Sector:', profile?.sector);

  const getFinvizField = field => {
    const fv = finvizMap[ticker] || {};
    const lbls = fv.allLabels || [];
    const vals = fv.allValues || [];
    const idx = lbls.findIndex(l => l?.trim() === field);
    return idx !== -1 ? vals[idx] : null;
  };

  const price = profile.price || parseNum(getFinvizField('Price')) || 0;
  const eps = profile.eps || null;
  let peRatio = ratios.priceToEarningsRatioTTM || null;
  if(!peRatio && eps && price) peRatio = price / eps;
  if(!peRatio) { const peStr = getFinvizField('P/E'); peRatio = parseNum(peStr); }

  const roe = metrics.returnOnEquityTTM || null;
  const profitMargin = ratios.netProfitMarginTTM || null;
  const beta = profile.beta || parseNum(getFinvizField('Beta')) || 1;
  const marketCap = profile.marketCap || parseNum(getFinvizField('Market Cap')) || 0;
  const companyName = profile.companyName || ticker;
  const sector = profile.sector || profile.industry || 'N/A';
  let high52w = price;
  if(profile.range) { const parts = profile.range.split('-'); high52w = parseFloat(parts[1]) || price; }

  const pasaFiltro = (peRatio > 0 && peRatio < 40 && (roe || profitMargin) && marketCap > 500000000);
  if(!pasaFiltro) {
    results.push({ json: { filtrado: false, Ticker: ticker, reason: 'FILTER', DataSource: 'FMP' } });
    continue;
  }

  let scoreFund = 0;
  if(peRatio < 15) scoreFund += 10;
  else if(peRatio < 25) scoreFund += 7;
  else if(peRatio < 40) scoreFund += 5;

  const roeVal = roe !== null ? roe : (parseNum(getFinvizField('ROE')) / 100);
  if(roeVal) {
    if(roeVal > 0.20) scoreFund += 10;
    else if(roeVal > 0.10) scoreFund += 7;
    else if(roeVal > 0.05) scoreFund += 3;
  }

  const pmVal = profitMargin !== null ? profitMargin : (parseNum(getFinvizField('Profit Margin')) / 100);
  if(pmVal) {
    if(pmVal > 0.20) scoreFund += 10;
    else if(pmVal > 0.10) scoreFund += 7;
    else if(pmVal > 0) scoreFund += 3;
  }

  let rsiVal = check._rsiAlpha;
  let rsiSource = check._rsiSource;
  if(rsiVal === null) {
    const rsiStr = getFinvizField('RSI (14)');
    rsiVal = parseNum(rsiStr);
    if(rsiVal !== null) rsiSource = 'Finviz';
  }

  let scoreTec = 0;
  if(rsiVal !== null) {
    if(rsiVal < 30) scoreTec += 18;
    else if(rsiVal < 40) scoreTec += 15;
    else if(rsiVal < 60) scoreTec += 10;
    else if(rsiVal < 70) scoreTec += 5;
  }

  const distHigh = high52w > 0 ? ((high52w - price) / high52w) * 100 : 0;
  if(distHigh > 20) scoreTec += 7;
  else if(distHigh < 5) scoreTec -= 5;

  const total = Math.round(scoreFund + scoreTec + 12.5);
  let senal = 'NEUTRAL';
  if(total >= 80) senal = 'COMPRA FUERTE';
  else if(total >= 60) senal = 'COMPRA';
  else if(total >= 40) senal = 'NEUTRAL';
  else senal = 'EVITAR';

  let perfil = 'Arriesgado';
  if(beta < 1 && marketCap > 10000000000) perfil = 'Conservador';

  results.push({ json: {
    filtrado: true,
    Fecha: new Date().toISOString().split('T')[0],
    Ticker: ticker,
    Empresa: companyName,
    Sector: sector,
    Precio: price,
    PE: peRatio !== null ? Number(peRatio).toFixed(2) : 'N/A',
    ROE: roeVal !== null ? (roeVal * 100).toFixed(2) + '%' : 'N/A',
    ProfitMargin: pmVal !== null ? (pmVal * 100).toFixed(2) + '%' : 'N/A',
    MarketCap: (marketCap / 1e9).toFixed(2) + 'B',
    Beta: Number(beta).toFixed(2),
    RSI: rsiVal !== null ? Number(rsiVal).toFixed(2) : 'N/A',
    RSI_Source: rsiSource,
    Dist52wHigh: distHigh.toFixed(1) + '%',
    Sentimiento: 'NEUTRAL',
    TieneSuper: 'N/A',
    Senal: senal,
    Score: total,
    Perfil: perfil,
    DataSource: 'FMP+Finviz'
  }});
}

console.log('Results:', results.length);
return results;

// Score Finviz - Fixed ticker lookup with sector fallback
const items = $input.all();
const results = [];
let fmpFailedItems = [];
try { fmpFailedItems = $('FMP Fallo?').all(); } catch (e) { console.log('FMP Fallo error:', e.message); }

console.log('=== Score Finviz Debug ===');
console.log('items:', items.length);
console.log('fmpFailedItems:', fmpFailedItems.length);

const parseNum = val => {
  if (!val || val === '-') return null;
  const cleaned = String(val).replace(/[%,]/g, '');
  const n = parseFloat(cleaned);
  return isNaN(n) ? null : n;
};
const parseMktCap = val => {
  if (!val) return 0;
  const n = parseFloat(val);
  if (isNaN(n)) return 0;
  if (val.includes('T')) return n * 1e12;
  if (val.includes('B')) return n * 1e9;
  if (val.includes('M')) return n * 1e6;
  return n;
};

for (let idx = 0; idx < items.length; idx++) {
  const item = items[idx];
  const labels = item?.json?.allLabels || [];
  const values = item?.json?.allValues || [];

  // Fixed: Use correct index to get ticker
  const fmpItem = fmpFailedItems[idx]?.json;
  const tickerName = fmpItem?._ticker || 'UNKNOWN';

  console.log('Processing Finviz ticker:', tickerName);

  const m = {};
  for (let i = 0; i < Math.min(labels.length, values.length); i++) {
    m[labels[i]] = values[i];
  }

  if (Object.keys(m).length < 5) {
    console.log('Not enough fields for:', tickerName);
    results.push({ json: { filtrado: false, Ticker: tickerName, reason: 'NO_FINVIZ', DataSource: 'Finviz' } });
    continue;
  }

  const price = parseNum(m['Price']) || 0;
  const peRatio = parseNum(m['P/E']) || 0;
  const roeRaw = parseNum(m['ROE']);
  const roe = roeRaw !== null ? roeRaw / 100 : 0;
  const pmRaw = parseNum(m['Profit Margin']);
  const profitMargin = pmRaw !== null ? pmRaw / 100 : 0;
  const beta = parseNum(m['Beta']) || 1;
  const marketCap = parseMktCap(m['Market Cap'] || '0');
  const rsiVal = parseNum(m['RSI (14)']);

  // Fixed: Get sector from Finviz - use 'Sector' field or try 'Industry'
  const sector = m['Sector'] || m['Industry'] || 'N/A';
  const company = m['Company'] || tickerName;

  console.log('Finviz Sector:', sector, 'Company:', company);

  let high52w = price;
  if (m['52W High']) high52w = parseFloat(String(m['52W High']).split(' ')[0]) || price;

  let scoreFund = 0;
  if(peRatio && peRatio < 15) scoreFund += 10;
  else if(peRatio && peRatio < 25) scoreFund += 7;
  else if(peRatio && peRatio < 40) scoreFund += 5;

  if(roe && roe > 0.20) scoreFund += 10;
  else if(roe && roe > 0.10) scoreFund += 7;
  else if(roe && roe > 0.05) scoreFund += 3;

  if(profitMargin && profitMargin > 0.20) scoreFund += 10;
  else if(profitMargin && profitMargin > 0.10) scoreFund += 7;
  else if(profitMargin && profitMargin > 0) scoreFund += 3;

  let scoreTec = 0;
  if(rsiVal !== null) {
    if(rsiVal < 30) scoreTec += 18;
    else if(rsiVal < 40) scoreTec += 15;
    else if(rsiVal < 60) scoreTec += 10;
    else if(rsiVal < 70) scoreTec += 5;
  }

  const distHigh = high52w > 0 ? ((high52w - price) / high52w) * 100 : 0;
  if(distHigh > 20) scoreTec += 7;
  else if(distHigh < 5) scoreTec -= 5;

  const total = Math.round(scoreFund + scoreTec + 12.5);
  let senal = 'NEUTRAL';
  if(total >= 80) senal = 'COMPRA FUERTE';
  else if(total >= 60) senal = 'COMPRA';
  else if(total >= 40) senal = 'NEUTRAL';
  else senal = 'EVITAR';

  let perfil = 'Arriesgado';
  if(beta < 1 && marketCap > 10000000000) perfil = 'Conservador';

  results.push({ json: {
    filtrado: true,
    Fecha: new Date().toISOString().split('T')[0],
    Ticker: tickerName,
    Empresa: company,
    Sector: sector,
    Precio: price,
    PE: Number(peRatio).toFixed(2),
    ROE: (roe * 100).toFixed(2) + '%',
    ProfitMargin: (profitMargin * 100).toFixed(2) + '%',
    MarketCap: (marketCap / 1e9).toFixed(2) + 'B',
    Beta: Number(beta).toFixed(2),
    RSI: rsiVal !== null ? Number(rsiVal).toFixed(2) : 'N/A',
    RSI_Source: 'Finviz',
    Dist52wHigh: distHigh.toFixed(1) + '%',
    Sentimiento: 'NEUTRAL',
    TieneSuper: 'N/A',
    Senal: senal,
    Score: total,
    Perfil: perfil,
    DataSource: 'Finviz'
  }});
}

console.log('Finviz Results:', results.length);
return results;
